import React, { useState } from 'react';
import { Modal } from './Modal';
import './styles.css';

export default function App() {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Accessible Modal</h1>
      <button data-testid="open-modal" className="btn btn--primary" onClick={() => setIsOpen(true)}>
        Open Modal
      </button>
      <Modal isOpen={isOpen} onClose={() => setIsOpen(false)}>
        <p style={{ marginBottom: '1rem', color: '#4b5563', lineHeight: 1.6 }}>
          Are you sure you want to proceed? This action cannot be undone.
        </p>
        <div style={{ display: 'flex', gap: '0.5rem', justifyContent: 'flex-end' }}>
          <button data-testid="modal-cancel" className="btn" onClick={() => setIsOpen(false)}>Cancel</button>
          <button data-testid="modal-confirm" className="btn btn--primary" onClick={() => setIsOpen(false)}>Confirm</button>
        </div>
      </Modal>
    </div>
  );
}

